#include <iostream>

int main() {
    int feet{};
    int inches{};
    // Your code here
    return 0;
}

solution_code:
#include <iostream>

int main() {
    int feet{};
    int inches{};
    std::cin >> feet >> inches;

    int total_inches{ feet * 12 + inches };

    std::cout << "Total inches: " << total_inches << '\n';

    return 0;
}

