#include <iostream>

int main() {
    int age{};
    // Your code here
    return 0;
}

solution_code:
#include <iostream>

int main() {
    int age{};
    std::cin >> age;

    std::cout << "You are " << age << " years old." << '\n';
    std::cout << "Next year you will be " << age + 1 << '.' << '\n';

    return 0;
}
